"""Embedded, dependency-free Auro operator console assets."""
from __future__ import annotations

HTML = r'''<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="color-scheme" content="dark"><title>Auro Operator Console</title><link rel="stylesheet" href="/console.css"></head>
<body><a class="skip" href="#main">Skip to workbench</a>
<header class="mast"><div><p class="eyebrow">AURUM ORGANISMUS XIV · AOX–HIM</p><h1>Auro operator console</h1><p class="lede">A sovereign instrument for model responses, native capabilities, and receipt-backed work.</p></div><div class="connection"><span id="light" aria-hidden="true"></span><span id="connection">Connecting</span></div></header>
<nav aria-label="Console sections"><a href="#workbench">Chat</a><a href="#context">Context</a><a href="#models">Models</a><a href="#registry">Tools</a><a href="#receipts">Receipts</a></nav>
<main id="main"><section class="rail" aria-label="Runtime status"><div><span>Service</span><strong id="service">—</strong></div><div><span>Active models</span><strong id="model">Discovering fleet…</strong></div><div><span>Logical context</span><strong id="contextTokens">—</strong></div><div><span>Proof posture</span><strong>Receipt-backed · local-first</strong></div></section>
<section class="panel setup"><p class="kicker">Connection</p><div class="credential-grid"><label>Read/API token<input id="apiToken" type="password" autocomplete="off" placeholder="Optional on loopback"></label><label>Execution token<input id="executionToken" type="password" autocomplete="off" placeholder="Required only for writes"></label><button id="connect" type="button" class="secondary">Connect</button></div><p class="muted">Credentials stay in this browser tab. Read access and execution authority are separate.</p></section>
<section id="workbench" class="grid"><div class="panel compose"><p class="kicker">01 · Chat</p><h2>Talk to HIM</h2><form id="ask"><label for="message">Objective</label><textarea id="message" required maxlength="12000" placeholder="Ask, build, research, reason, or continue prior work…"></textarea><div class="execute"><label><input id="execute" type="checkbox"> Allow governed execution for this turn</label></div><button type="submit">Send to HIM <span aria-hidden="true">→</span></button></form></div>
<article class="panel response" aria-live="polite"><div class="response-head"><div><p class="kicker">02 · Response</p><h2 id="responseTitle">Awaiting an objective</h2></div><span id="confidence"></span></div><div id="answer" class="answer"><p class="muted">The response, bounded reasoning summary, internal council, proposed actions, and receipt will appear here.</p></div><details><summary>Evidence and council</summary><pre id="evidence">No response yet.</pre></details></article></section>
<section id="context" class="section"><div class="section-head"><div><p class="kicker">03 · Python context virtualization</p><h2>Teach HIM without flooding attention</h2></div><strong id="contextStat">No documents</strong></div><form id="teach"><label for="source">Source name</label><input id="source" value="operator-note" maxlength="240"><label for="knowledge">Knowledge or document text</label><textarea id="knowledge" maxlength="900000" placeholder="Paste documentation, research, project history, or operating knowledge…"></textarea><button type="submit">Index into persistent context</button></form><pre id="contextResult">Logical storage may exceed the active model window; each turn receives a ranked bounded working set.</pre></section>
<section id="models" class="section"><div class="section-head"><div><p class="kicker">04 · Real model fleet</p><h2>Configured model lanes</h2></div></div><div id="modelList" class="registry"></div></section>
<section id="registry" class="section"><div class="section-head"><div><p class="kicker">05 · Native substrate</p><h2>Capability registry</h2></div><label class="search">Filter <input id="filter" type="search" placeholder="organ, capability, mode"></label></div><div id="capabilities" class="registry" aria-live="polite"></div></section>
<section id="receipts" class="section receipts"><div class="section-head"><div><p class="kicker">06 · Chain of custody</p><h2>Receipt room</h2></div><button id="verify" class="secondary">Verify chain</button></div><p id="verification" class="muted">Not yet verified.</p><div id="receiptList" class="receipt-list"></div></section></main>
<footer><p>Auro14B · HIM — NOVA / MESIE lineage</p><p>Paper/testnet finance only · integrity vault is not encrypted custody</p></footer><script src="/console.js" defer></script></body></html>'''

CSS = r''':root{--canvas:#10110f;--surface:#171915;--raised:#20231d;--ink:#f1eee4;--muted:#aaa99e;--quiet:#777b70;--signal:#d9a441;--good:#6fb58a;--danger:#d76d61;--rule:#34382f;--focus:#f2c66d;font-family:Inter,ui-sans-serif,system-ui,sans-serif;color:var(--ink);background:var(--canvas)}*{box-sizing:border-box}html{scroll-behavior:smooth}body{margin:0;min-width:320px;background:var(--canvas);line-height:1.55}.skip{position:fixed;left:12px;top:-60px;background:var(--ink);color:var(--canvas);padding:8px 12px;z-index:10}.skip:focus{top:12px}.mast{max-width:1280px;margin:auto;padding:64px 32px 40px;display:flex;justify-content:space-between;gap:32px;align-items:flex-start;border-bottom:1px solid var(--rule)}h1,h2,p{margin-top:0}h1{font:400 clamp(2.4rem,6vw,5.8rem)/.95 Georgia,serif;max-width:760px;letter-spacing:-.045em;margin-bottom:24px}h2{font:400 clamp(1.55rem,3vw,2.4rem)/1.1 Georgia,serif;letter-spacing:-.025em}.eyebrow,.kicker{font:700 .68rem/1.2 ui-monospace,monospace;letter-spacing:.15em;text-transform:uppercase;color:var(--signal)}.lede{color:var(--muted);max-width:650px;font-size:1.05rem}.connection{display:flex;align-items:center;gap:9px;white-space:nowrap;color:var(--muted);font-size:.8rem}#light{width:8px;height:8px;background:var(--signal);display:inline-block}#light.ok{background:var(--good)}#light.bad{background:var(--danger)}nav{max-width:1280px;margin:auto;padding:14px 32px;display:flex;gap:24px;border-bottom:1px solid var(--rule);position:sticky;top:0;background:rgba(16,17,15,.96);z-index:5}nav a{color:var(--muted);font-size:.78rem;text-decoration:none}nav a:hover{color:var(--ink)}main{max-width:1280px;margin:auto;padding:32px}.rail{display:grid;grid-template-columns:repeat(4,1fr);border:1px solid var(--rule);margin-bottom:32px}.rail div{padding:14px 16px;border-right:1px solid var(--rule)}.rail div:last-child{border:0}.rail span{display:block;color:var(--quiet);font-size:.68rem;text-transform:uppercase;letter-spacing:.08em}.rail strong{font-size:.82rem;font-weight:600}.grid{display:grid;grid-template-columns:minmax(300px,.85fr) minmax(0,1.4fr);gap:16px}.panel,.section{border:1px solid var(--rule);background:var(--surface);padding:28px}.compose{align-self:start;position:sticky;top:68px}label{display:block;color:var(--muted);font-size:.76rem;margin-bottom:8px}textarea,input[type=search],input[type=password]{width:100%;background:var(--canvas);border:1px solid var(--rule);border-radius:2px;color:var(--ink);font:inherit;padding:12px}textarea{min-height:210px;resize:vertical}textarea:focus,input:focus,button:focus,summary:focus,a:focus{outline:2px solid var(--focus);outline-offset:3px}.execute{margin:16px 0}.execute label{display:flex;gap:8px;align-items:center}.execute input[type=password]{margin-top:12px}button{border:1px solid var(--signal);border-radius:2px;background:var(--signal);color:#17130b;padding:11px 15px;font:700 .78rem/1 system-ui;cursor:pointer}button:hover{filter:brightness(1.08)}button:disabled{opacity:.5;cursor:wait}.secondary{background:transparent;color:var(--ink);border-color:var(--rule)}.response{min-height:510px}.response-head,.section-head{display:flex;justify-content:space-between;gap:24px;align-items:flex-start}.answer{font-size:1rem;max-width:72ch;white-space:pre-wrap}.muted{color:var(--muted)}details{border-top:1px solid var(--rule);margin-top:28px;padding-top:16px}summary{cursor:pointer;color:var(--muted);font-size:.8rem}pre{white-space:pre-wrap;overflow:auto;color:#c9cbbf;background:var(--canvas);padding:16px;font:12px/1.55 ui-monospace,monospace;max-height:420px}.section{margin-top:16px}.search{width:min(280px,40%)}.registry{border-top:1px solid var(--rule)}.cap{display:grid;grid-template-columns:minmax(180px,1fr) 120px 90px minmax(240px,1.5fr);gap:16px;padding:14px 0;border-bottom:1px solid var(--rule);align-items:start}.cap code{color:var(--ink);font-size:.8rem}.tag{font:700 .62rem/1 ui-monospace,monospace;text-transform:uppercase;color:var(--signal)}.cap p{color:var(--muted);font-size:.78rem;margin:0}.receipt-list{display:grid;gap:8px}.receipt{display:grid;grid-template-columns:140px 1fr 90px;gap:16px;padding:10px 0;border-top:1px solid var(--rule);font:12px/1.4 ui-monospace,monospace;color:var(--muted)}.receipt code{overflow:hidden;text-overflow:ellipsis}footer{max-width:1280px;margin:32px auto 0;padding:24px 32px 48px;border-top:1px solid var(--rule);display:flex;justify-content:space-between;color:var(--quiet);font-size:.7rem}footer p{margin:0}@media(max-width:800px){.mast{padding-top:40px;display:block}.connection{margin-top:24px}.rail{grid-template-columns:1fr 1fr}.rail div:nth-child(2){border-right:0}.rail div:nth-child(-n+2){border-bottom:1px solid var(--rule)}.grid{grid-template-columns:1fr}.compose{position:static}.cap{grid-template-columns:1fr 80px}.cap p{grid-column:1/-1}.search{width:100%}.section-head{display:block}.receipt{grid-template-columns:1fr}.mast,main,nav,footer{padding-left:18px;padding-right:18px}footer{display:block}footer p+ p{margin-top:8px}}@media(prefers-reduced-motion:reduce){html{scroll-behavior:auto}}'''

CSS += r'''.setup{margin-bottom:16px}.credential-grid{display:grid;grid-template-columns:1fr 1fr auto;gap:12px;align-items:end}.credential-grid label{margin:0}.credential-grid input,input:not([type]){width:100%;background:var(--canvas);border:1px solid var(--rule);color:var(--ink);font:inherit;padding:12px}.setup p:last-child{margin:12px 0 0}#teach{display:grid;gap:10px;max-width:900px}#teach textarea{min-height:150px}.model-row{display:grid;grid-template-columns:1fr 1fr 1fr 2fr;gap:14px;padding:14px 0;border-bottom:1px solid var(--rule);font-size:.78rem}.model-row span{color:var(--muted)}@media(max-width:800px){.credential-grid,.model-row{grid-template-columns:1fr}}'''

JS = r'''const $=s=>document.querySelector(s);const state={caps:[],models:[]};
async function api(path,options={}){options.headers={...auth(false),...(options.headers||{})};const r=await fetch(path,options);let data={};try{data=await r.json()}catch{}if(!r.ok){const e=data.error;throw new Error(data.detail||(typeof e==='object'?(e.message||e.code):e)||`HTTP ${r.status}`)}return data}
function auth(execution=false){const h={};const read=$('#apiToken')?.value;if(read)h.authorization=`Bearer ${read}`;const write=$('#executionToken')?.value;if(execution&&write)h['x-auro-execution-token']=write;return h}
function esc(v){return String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
async function boot(){try{const h=await api('/health');$('#service').textContent=h.service;$('#connection').textContent='Runtime online';$('#light').className='ok';await loadPrivate()}catch(e){$('#connection').textContent='Runtime unavailable';$('#light').className='bad';$('#answer').innerHTML=`<p class="muted">${esc(e.message)}</p>`}}
async function loadPrivate(){try{const [c,r,m,x]=await Promise.all([api('/v1/capabilities'),api('/v1/receipts'),api('/v1/models'),api('/v1/context')]);state.caps=c.capabilities;state.models=m.data;renderCaps();renderModels();renderReceipts(r.receipts);$('#contextTokens').textContent=Number(x.logical_tokens).toLocaleString()+' tokens';$('#contextStat').textContent=`${x.documents} documents · ${x.chunks} chunks`}catch(e){$('#connection').textContent='Connected · authentication needed';$('#answer').innerHTML=`<p class="muted">${esc(e.message)}</p>`}}
function renderCaps(){const q=$('#filter').value.toLowerCase();const rows=state.caps.filter(c=>JSON.stringify(c).toLowerCase().includes(q));$('#capabilities').innerHTML=rows.map(c=>`<article class="cap"><code>${esc(c.name)}</code><span class="tag">${esc(c.organ)}</span><span class="tag">${c.approval_required?'approval':'read'}</span><p>${esc(c.description)}</p></article>`).join('')||'<p class="muted">No matching capabilities.</p>'}
function renderModels(){const rows=state.models;$('#model').textContent=rows.length?`${rows.length} lane${rows.length===1?'':'s'} · ${rows[0].id}`:'No model';$('#modelList').innerHTML=rows.map(m=>`<article class="model-row"><strong>${esc(m.id)}</strong><span>${esc(m.role)}</span><span>${m.local?'local':'remote'} · ${esc(m.provider)}</span><span>${m.parameter_count_verified?Number(m.parameter_count).toLocaleString()+' verified parameters':'parameter count unverified'}<br>${esc((m.capabilities||[]).join(', '))}</span></article>`).join('')||'<p class="muted">No configured model lanes.</p>'}
function renderReceipts(rows=[]){$('#receiptList').innerHTML=rows.map(r=>{const h=r.receipt_hash||r.hash;return `<div class="receipt"><span>${esc(r.kind||r.operation)}</span><code title="${esc(h)}">${esc(h)}</code><span>${r.ok?'accepted':'denied'}</span></div>`}).join('')||'<p class="muted">No receipts recorded in this process.</p>'}
$('#connect').addEventListener('click',loadPrivate)
$('#filter').addEventListener('input',renderCaps)
$('#ask').addEventListener('submit',async e=>{e.preventDefault();const btn=e.submitter;btn.disabled=true;$('#responseTitle').textContent='Council working…';$('#answer').innerHTML='<p class="muted">Retrieving context, routing models, deliberating, and verifying.</p>';try{const execute=$('#execute').checked;const data=await api('/v1/respond',{method:'POST',headers:{'content-type':'application/json',...auth(execute)},body:JSON.stringify({message:$('#message').value,execute})});$('#responseTitle').textContent='HIM response';$('#confidence').textContent=`${Math.round(data.confidence*100)}% confidence`;$('#answer').textContent=data.answer;$('#evidence').textContent=JSON.stringify({context:data.context,models_used:data.models_used,routing_traces:data.routing_traces,reasoning_summary:data.reasoning_summary,agents:data.agents,proposed_actions:data.proposed_actions,executions:data.executions,receipt:data.receipt},null,2);await Promise.all([refreshReceipts(),loadPrivate()])}catch(err){$('#responseTitle').textContent='Request failed';$('#answer').innerHTML=`<p class="muted">${esc(err.message)}</p>`}finally{btn.disabled=false}})
$('#teach').addEventListener('submit',async e=>{e.preventDefault();const btn=e.submitter;btn.disabled=true;try{const data=await api('/v1/context/ingest',{method:'POST',headers:{'content-type':'application/json',...auth(true)},body:JSON.stringify({text:$('#knowledge').value,source:$('#source').value,kind:'document',importance:.7})});$('#contextResult').textContent=JSON.stringify(data,null,2);$('#knowledge').value='';await loadPrivate()}catch(err){$('#contextResult').textContent=err.message}finally{btn.disabled=false}})
async function refreshReceipts(){const r=await api('/v1/receipts');renderReceipts(r.receipts)}
$('#verify').addEventListener('click',async()=>{try{const r=await api('/v1/receipts/verify');$('#verification').textContent=r.valid?`Chain valid · ${r.count??'all'} receipts checked`:`Chain invalid · sequence ${r.failed_sequence||'unknown'}`}catch(e){$('#verification').textContent=`Verification failed · ${e.message}`}})
document.addEventListener('keydown',e=>{if((e.ctrlKey||e.metaKey)&&e.key==='Enter')$('#ask').requestSubmit()});boot();'''

ASSETS = {
    "/": ("text/html; charset=utf-8", HTML.encode()),
    "/console": ("text/html; charset=utf-8", HTML.encode()),
    "/console.css": ("text/css; charset=utf-8", CSS.encode()),
    "/console.js": ("text/javascript; charset=utf-8", JS.encode()),
}
